"use strict";(self.webpackChunkpersonal_site=self.webpackChunkpersonal_site||[]).push([[964],{964:function(e,t,n){n.r(t);var a=n(8683),o=(n(2791),n(1523)),r=n(2068),i=n.n(r),s=n(6842),d=n(184),c="\n# Intro\n\n\u03a7\u03c1\u03b9\u03c3\u03c4\u03af\u03bd\u03b1 \u039f\u03b2\u03b5\u03b6\u03af\u03ba <- my actual name \n\n# Currently\nI live in Edinburgh, Scotland. I work as a Research Engineer at the [Blockchain Technology Lab](https://www.ed.ac.uk/informatics/blockchain) at the University of Edinburgh, where I get to write code and papers (cool, right?). I'm participating in this year's iteration of the [Young Leaders Development Programme](https://www.2050.scot/yldp) with the hopes of learning more about the climate emergency and finding the courage to be more vocal about it. I recently started volunteering as a mentor at [Prewired](https://www.prewired.org/), an Edinburgh-based programming club for children and teenagers.\n\n# In the past\nI grew up in Crete, Greece. I moved to the north of Greece for my studies, and after that I moved to the south of France for my first job. After a brief return to Crete, I decided to abandon warm weather for good and moved to Scotland to pursue an MSc. And then I stayed there.  \n\n\n# I like\n\n- The blue sea\n- Chocolate\n- Yoga\n- Summer\n- [Books](https://app.thestorygraph.com/profile/ladychristina)\n- Podcasts ([Lex Fridman](https://lexfridman.com/podcast/), [Huberman Lab](https://hubermanlab.com/), [The Tim Ferriss Show](https://tim.blog/podcast/), and others)\n- Cycling\n- Baking\n\n\n\n# Fun facts about me\n\n- I AM A LADY (just in case you hadn't noticed already) \x3c!-- todo maybe add link to certificate --\x3e\n- In 2021, I resolved to visit at least one new Greek island each year for the next 50 years\n- (After endless practicing during lockdown) I can do a headstand and hold it for a minute \n- I can say thank you in more than 20 languages (thanks to all my international colleagues \ud83d\ude4f)\n- I always thought I would do well at an eating contest but never had the chance to (dis)prove myself\n- Last year I managed to eliminate plastic from my bathroom and I'm very proud of it  \x3c!-- todo maybe link to notion page about sustainable consumption --\x3e\n- I used to dislike tea before coming to live in the UK, but two years into it and I probably qualify as a tea addict now \x3c!-- todo maybe mention facourite tea brand --\x3e\n- I have taken the [Giving What We Can](https://www.givingwhatwecan.org/pledge) trial pledge to donate at least 2% of my income this year \n- I enjoy climbing and want to get better at it\n",l=c.split(/\s+/).map((function(e){return e.replace(/\W/g,"")})).filter((function(e){return e.length})).length,h=function(e){var t=Object.assign({},e);return(0,d.jsx)(o.rU,(0,a.Z)({},t))};t.default=function(){return(0,d.jsx)(s.Z,{title:"About",description:"Learn about Christina Ovezik",children:(0,d.jsxs)("article",{className:"post markdown",id:"about",children:[(0,d.jsx)("header",{children:(0,d.jsxs)("div",{className:"title",children:[(0,d.jsx)("h2",{"data-testid":"heading",children:(0,d.jsx)(o.rU,{to:"/about",children:"About Me"})}),(0,d.jsxs)("p",{children:["(in about ",l," words)"]})]})}),(0,d.jsx)(i(),{source:c,renderers:{Link:h},escapeHtml:!1})]})})}}}]);
